var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"크윽! 역시 마스터 말대로 4종은 꽤 만만치 않은데?","JPN":"くっ！　さすがの第4種は、マスターの言うとおり手強いようだな？","ENG":"Kgh! It's just like Master said. A Category 4 isn't as easy as I thought it would be.","TWN":"咳呃！不愧是是4類侵蝕體，跟大姊說的一樣難對付呢？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"하지만 원래 쥐새끼는 궁지에 몰리면 몰릴 수록 눈에 뵈는 게 없어 진단 말이지!","JPN":"でも、ドブネズミは追い詰められれば追い詰められるほど、大胆になっていくもんなんだよ！","ENG":"But rats normally act like they have nothing to lose when they're cornered against a wall!","TWN":"但是，老鼠越是被逼入絕境，越是會拼命反抗！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아포리아의 공격을 흡수하고 있잖아?","JPN":"アポリアの攻撃を吸収している？","ENG":"She's absorbing Aporia's attacks?","TWN":"她在吸收阿波利亞的攻擊？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신, 대체 누구죠? 어째서 당신이 델타 세븐의 대원복을?","JPN":"あなたはいったい？　どうしてデルタセブンの制服を？","ENG":"Hey, who are you? How come you're wearing a Delta Seven uniform?","TWN":"你，你到底是誰？為什麼穿著第七三角洲部隊的隊服？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"하고 싶은 말은 많지만!","JPN":"言いたいことはたくさんあるけどよ！","ENG":"There's a lot I want to say, but!","TWN":"雖然我也有很多話想說！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"그런 잡소리는 바쁘니까, 나중에 하자고!","JPN":"そんな雑談は、また後にしようぜ！","ENG":"Let's talk about that after we're done here, okay?","TWN":"但我現在很忙，之後再閒聊吧！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"마스터! 아직 멀었어?","JPN":"マスター！　まだなのか？","ENG":"Master! What's taking so long?","TWN":"大姊！還沒到嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"저길 봐! 함선이야! 하늘에서 커다란 함선이 나타났어!","JPN":"あれを見ろ！　艦船だ！　空から巨大な艦船が現れたぞ！","ENG":"Look over there! It's a ship! A huge ship appeared from the sky!","TWN":"看那邊！是艦船！天空中出現了巨型艦船！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"함선? 그렇지만 뉴 오하이오는 완파됐을 텐데?","JPN":"艦船？　しかしニューオハイオは完全に壊れたんじゃなかったのか？","ENG":"A ship? But New Ohio was blown to bits!","TWN":"艦船？但新俄亥俄已經完全被毀了啊？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저건…… 아이기스!","JPN":"あれは……アイギス！","ENG":"That's... Aegis!","TWN":"那是……埃癸斯！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇다는 말은 안토노프?","JPN":"ということは、アントノフ？","ENG":"That means, it's Antonov?","TWN":"也就是說，安東諾夫來了？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"구해주는 게 벌써 두 번째군, 소령.","JPN":"助けるのは二度目だな、少佐。","ENG":"It is already the second time I have saved you, Major.","TWN":"這已經是我第二次救你了，少校。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"전 대원, 지금부터 퇴로를 확보하도록 하지. 깔려 죽고 싶지 않으면 뛰게.","JPN":"全隊員、今より退路を確保する。下敷きになって死にたくなかったら走るように。","ENG":"All units, I will secure an escape route. Run if you do not want to get crushed.","TWN":"全體隊員，現在往後退開，不想被壓死的話就動起來。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"레베카, 팔라디움 방벽을 사출한다. 자력 능력으로 낙하 위치를 보정하도록.","JPN":"レベッカ、パラディウム防壁を射出する。磁力能力で落下位置を補正してくれ。","ENG":"Rebecca, ejecting the Palladium bulwark. Calibrate the position of the drop using your magnetic force.","TWN":"蕾貝卡，我將發射守護神屏障。你用磁力來校正降落位置。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"알았으니까, 뜸들이지 말고 빨랑 던져, 마스터!!","JPN":"了解、わかったからさっさと投げてくれ、マスター！！","ENG":"Fine. Stop hesitating and throw it down already, Master!!","TWN":"知道知道，別賣關子了，快點扔下來，大姊！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"하늘의 함선에서 뭔가 떨어진다!","JPN":"空の艦船から何かが落ちてくるぞ！","ENG":"Something's falling from the ship in the sky!","TWN":"有什麼東西從空中的艦船上掉下來了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"벼, 벽이야! 하늘에서 커다란 벽이 낙하하고 있어!","JPN":"か、壁だ！　空から巨大な壁が落ちてきている！","ENG":"I-It's a wall! A gigantic wall is dropping from the sky!","TWN":"是，是牆！從天空中掉下來好大一道牆！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"이쪽으로 떨어진다!! 피해!!","JPN":"こっちに落ちてくるぞ！　逃げろ！","ENG":"It's falling toward here!! RUN!!","TWN":"往這邊掉下來了！！快躲開！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"나이스 캐치! 쳇, 더럽게 무겁네.","JPN":"ナイスキャッチ！　ったく、何て重さだよ。","ENG":"Got it! Tch! This thing's so frickin' heavy!","TWN":"好球！嘖，這玩意還真是重。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"말도 안 돼! 저 정도의 질량 병기가 낙하하는 중에 궤도를 바꿨다고?","JPN":"信じられない！　あれほどの質量兵器が落下途中で軌道を変えるなんて。","ENG":"Unbelievable! Changing the trajectory of such a massive weapon during free fall?","TWN":"不可能！那種品質的兵器居然在降落途中改變了軌道？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"서두르게, 소령. 어차피 이런 건 임시방편이야.","JPN":"急いでくれ、少佐。こんなものは一時しのぎにしかならない。","ENG":"Hurry, Major. This is only a temporary solution.","TWN":"撤退，少校！這只能暫時抵擋一下。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아이기스, 방벽이 사출된 좌표에 전장 소각을 개시한다. 입자포 발사!","JPN":"アイギス、防壁が射出された座標に戦場焼却を開始する。粒子砲発射！","ENG":"Aegis, incinerate the battlefield at the location where the bulwark was ejected. Discharging Particle gun!","TWN":"埃癸斯，從屏障發射的座標開始，轟炸戰場。粒子炮，發射！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전 대원! 아포리아 공략 작전은 실패했습니다.","JPN":"全隊員！　アポリア攻略作戦は失敗です。","ENG":"All units! The operation was a failure.","TWN":"全體隊員！阿波利亞作戰失敗。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"거점기지까지 퇴각합니다!","JPN":"拠点基地まで退却します！","ENG":"Retreat to base!","TWN":"撤退至基地！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"하아…… 하아…… 하아……!","JPN":"はあ……はあ……はあ……！","ENG":"*Huff*... *Huff*... *Huff*...!","TWN":"哈啊……哈啊……哈啊……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"젠장할, 벽에 막힌 침식체들이 관측소를 우회해서 이쪽을 쫓아올 줄이야.","JPN":"くそ、壁で行き場を失った侵食体どもが観測所を迂回してこっちまで来るとはな。","ENG":"Dammit, didn't expect the C.O.s that were blocked by the wall to circumnavigate the observatory and pursue in this direction.","TWN":"可惡，被牆堵住的侵蝕體，竟然繞過觀測站往這邊追來了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면 그때, 그 망할 여자를 따라갔었어야 했는데.","JPN":"こんなことなら、さっきあのクソ女についていくんだった。","ENG":"If I knew this was going to happen, I should've followed that damned woman.","TWN":"早知道這樣，那時就該跟著那個女人。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mmm?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>…….</color>","JPN":"<color=#ff3636>……</color>","ENG":"<color=#ff3636>...</color>","TWN":"<color=#ff3636>……</color>"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L9_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"하아, 제기랄! 끝까지 운도 지지리……!","JPN":"はぁ、くっそ！　最後の最後までついてね……！","ENG":"Ugh, dammit! Just my lu–","TWN":"哈，該死！真是有夠倒楣的……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"으아아악!! 팔이!! 내 팔이!!","JPN":"うわぁあっ！！　腕が！！　俺の腕が！！","ENG":"AAAAGH!! MY ARM!! MY ARM!!!","TWN":"啊啊啊啊！！手臂！！我的手臂！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"개자식!! 내가 그냥, 그냥 죽을 것 같아!! 이 괴물아!!","JPN":"こいつ！！　この俺が何もせず、このまま大人しく死ぬと思ったら大間違いだ！！　化け物め！！","ENG":"You bastard!! You think I'm gonna just drop dead?! You monster!!","TWN":"混蛋！！你以為我會乖乖認命嗎！！你這個怪物！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"난 절대 곱게는 안 죽어!! 코쿤 프로토콜 실행!!","JPN":"ただじゃ死んでやらんぞ！！　コクーンプロトコール実行！","ENG":"I'm taking you with me!! Executing cocoon protocol!!","TWN":"我絕不會就這樣死的！！執行防護協議！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"흐하하하하하!! 성공했나? 혹시 몰라서 준비해둔 게 역시 정답이었군!","JPN":"ふははははは！！　成功か？　やっぱりもしもの場合に備えておいて正解だったな！","ENG":"Mwa ha ha ha!! Did it work? I knew it was the right answer to prepare this in advance!","TWN":"哈哈哈哈哈哈！！成功了嗎？以防萬一準備的，沒想到還真有用！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"이곳 관측소 근처에 모든 네피림 고치에 순도 높은 이터니움 정제액을 주입했다!","JPN":"この観測所周辺にあるネフィリムの繭全部に、高純度のエタニウム精製水を注入してやったぞ！","ENG":"I injected all the Nephil cocoons near this observatory with a high concentration of purified Ethereum liquid!","TWN":"我在這觀測站附近的所有諾菲力繭裡，都注入了高純度永恆之金錠！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"네피림!! 아포리아!!","JPN":"ネフィリム！！　アポリア！！","ENG":"Nephil!! APORIA!!","TWN":"諾菲力！！阿波利亞！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"내 사업을 망치고, 내 인생까지 망쳐버린 이 빌어먹을 괴물 자식들!","JPN":"よくも俺のビジネスを潰し、人生までめちゃくちゃにしてくれたな！　この化け物ども！","ENG":"First you ruined my business and now my life too! You monsters!","TWN":"你們這些該死的怪物，毀了我的事業，毀了我的人生！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"세상이 끝나는 그 순간까지! 서로 뒤엉켜서 물고 뜯어가며 싸워보라고!","JPN":"世界が終わる瞬間まで！　仲間同士でぐちゃぐちゃになって喧嘩してろ！","ENG":"Until the end of time! You're all going to get tangled up, fight, and kill each other!","TWN":"你們就相互廝殺！直到世界毀滅為止吧！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"아하, 아하하하하하핫……","JPN":"あは、あははははははっ……","ENG":"Ha ha... Aha ha ha ha...!","TWN":"哇哈哈哈哈哈哈哈……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"잠깐, 다들 정지!","JPN":"ちょっと待って、みんなストップ！","ENG":"Wait, everyone stop!","TWN":"等等，大家暫停行動！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L31_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"이 파장은 네피림이야!","JPN":"この波状はネフィリムだ！","ENG":"This wavelength is a Nephil!","TWN":"這個波長是諾菲力！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"제5 방위선에 네피림이 출현했어! 그것도 한 마리가 아니야!","JPN":"第5防衛線にネフィリムが出現したぞ！　しかも何体もいる！","ENG":"A Nephil appeared in the 5th Defense Line! Wait, it's not just one!","TWN":"第五防線出現了諾菲力！而且不止一隻！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐라고요? 그게 대체 무슨 소리에요, 박사님!?","JPN":"え？　どういうことですか、博士！？","ENG":"What? What are you talking about, Doctor?!","TWN":"你說什麼？那是什麼意思，博士？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"나도 몰라! 지금 그 구역에 있던 네피림 고치 세 개가 갑자기 동시에 부화했어!","JPN":"僕にもわからない！　今その区域にあったネフィリムの繭三つが同時に孵化したんだ！","ENG":"I dunno! But 3 cocoons just hatched in that area simultaneously!","TWN":"我也不清楚！現在這個區域的三個諾菲力繭突然同時孵化了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"이런 일이 어떻게!?","JPN":"どうして、こんなことに！？","ENG":"But how?!","TWN":"這種事情怎麼可能？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아포리아 하나만으로도 그 고생을 했는데 네피림까지.","JPN":"アポリア単体でもあれだけ強かったのに、ネフィリムまで。","ENG":"We're already tied up with Aporia, but now Nephils?","TWN":"光是一個阿波利亞就很難對付了，現在還加上諾菲力，"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이런 걸 엎친 데 덮친 격이라고 해야겠죠?","JPN":"泣きっ面に蜂とはこのことですね。","ENG":"So this is what they mean by adding insult to injury, right?","TWN":"這就叫作雪上加霜吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"잠깐, 뭔가 이상해. 네피림으로부터 교전 반응!","JPN":"待ってくれ、何かが変だ。ネフィリムから交戦反応！","ENG":"Wait, something's weird. I'm detecting a skirmish from the Nephils!","TWN":"等一下，有點奇怪。諾菲力附近出現交戰反應！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"설마!? 제이콥, 이 미친 자식이!?","JPN":"まさか！？　ジェイコブ、あのイカレ野郎！","ENG":"It can't be...! Jacob, you maniac!!","TWN":"難道是！？雅各，你這個瘋子！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"왜 그러시죠? 뭔가 짚이는 게 있으신가요? 박사님?","JPN":"どうしたんですか？　何か心当たりがあるんですか、博士？","ENG":"What is it? Do you have an idea of what's going on, Doctor?","TWN":"怎麼了？是猜到什麼了嗎？博士？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"좋게 말하면, 우린 시간을 벌었을지도 몰라.","JPN":"良く言えば、僕たちは時間を稼げたのかもしれない。","ENG":"On the bright side, we might have bought ourselves some time.","TWN":"往好處想，說不定我們爭取到了時間。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"일반적인 침식체와 달리, 아포리아의 목적은 네피림의 핵을 흡수하는 거야.","JPN":"普通の侵食体とは違って、アポリアの目的はネフィリムの核を吸収することだ。","ENG":"Unlike normal C.O.s, Aporia's goal is to absorb the Nephils' cores.","TWN":"與普通侵蝕體不同，阿波利亞的目的是吸收諾菲力核心。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"지금까지는 움직이지 않는 고치만 노렸지만, 네피림이 세 마리나 깨어난 이상 그렇게 쉽게 핵을 흡수할 수는 없겠지.","JPN":"今までは動かない繭だけを狙っていたけど、ネフィリムが3匹も生まれたからには、そう簡単に核を吸収することはできないはずだ。","ENG":"It has only been choosing immobile cocoons, but with 3 Nephils already hatched, it can't so easily absorb them now.","TWN":"在這之前，繭全都處於未孵化狀態，但現在諾菲力一下喚醒了三隻，他就無法再輕易地吸收核心了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그렇다면 지금 아포리아와 네피림이 서로 싸우고 있다는 말인가요?","JPN":"じゃ、じゃあ今、アポリアとネフィリムが戦っているということなんですか？","ENG":"Th-then you're saying that Aporia and the Nephils are fighting each other?","TWN":"那就是說，現在阿波利亞正在和諾菲力交戰嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"맞아. 네피림이 죽든, 아포리아가 죽든 둘 중 하나겠지.","JPN":"そのとおり、ネフィリムが死ぬか、アポリアが死ぬかのどちらかになるだろうな。","ENG":"Right. And one of them is going to die. Whether it be the Nephils or Aporia.","TWN":"沒錯。諾菲力和阿波利亞，能活下來的只有一方。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"하지만 제이콥 그 자식이 네피림을 깨우는 방법을 알고 있다는 건, 설마.","JPN":"でも、ジェイコブのやつがネフィリムを孵化させる方法を知っていたということは、まさか。","ENG":"But seeing how Jacob knew how to wake up the Nephil, does it mean that...","TWN":"但是雅各那傢伙怎麼知道喚醒諾菲力的方法……難道第一隻也是他……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"왜 그러세요, 박사님?","JPN":"どうしたんですか、博士？","ENG":"What's wrong, Doc?","TWN":"你怎麼了，博士？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아니. 됐어.","JPN":"いいや、何でもない。","ENG":"No, never mind.","TWN":"不，算了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어차피 추측일 뿐이고, 이제와서는 그다지 중요하지도 않아.","JPN":"推測でしかないし、こうなったらもう重要じゃない。","ENG":"It's all speculation, and it's not that important right now.","TWN":"反正也只是我的推測，現在這些不重要。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"중요한 건……","JPN":"重要なのは……","ENG":"What is important, however, is...","TWN":"重要的是……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"저 둘 중 어느 쪽이 이기든, 이제 이 세상은 끝장이라는 거겠지.","JPN":"どちらが勝つにせよ、もうこの世界には後がないということだな。","ENG":"That whichever side wins, this world is now doomed.","TWN":"不管他們哪方勝利，這個世界都要完蛋了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};